package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
)

// QuerySLBAndExport runs:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It returns the jq stdout (same content written to outputFile) and any error.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Ensure parent dir exists (optional but helpful).
	if dir := filepath.Dir(outputFile); dir != "." {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return "", fmt.Errorf("create output directory: %w", err)
		}
	}

	// Build pipeline without invoking a shell to avoid injection.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe: aliyun stdout -> jq stdin
	var pipeErr error
	jqCmd.Stdin, pipeErr = aliyunCmd.StdoutPipe()
	if pipeErr != nil {
		return "", fmt.Errorf("create pipe: %w", pipeErr)
	}

	// Capture stderr for diagnostics
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Capture jq stdout (this is what we also write to file)
	var jqOut bytes.Buffer
	jqCmd.Stdout = &jqOut

	// Start processes
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("start aliyun: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("start jq: %w (aliyun stderr: %s)", err, aliyunStderr.String())
	}

	// Wait for completion
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	// If either failed, return combined diagnostics
	if aliyunErr != nil || jqErr != nil {
		return jqOut.String(), fmt.Errorf(
			"pipeline failed: aliyunErr=%v jqErr=%v aliyunStderr=%s jqStderr=%s",
			aliyunErr, jqErr, aliyunStderr.String(), jqStderr.String(),
		)
	}

	// Write output to file (equivalent to shell redirection)
	if err := os.WriteFile(outputFile, jqOut.Bytes(), 0o644); err != nil {
		return jqOut.String(), fmt.Errorf("write output file: %w", err)
	}

	return jqOut.String(), nil
}

func main() {
	// Example usage (optional):
	// out, err := QuerySLBAndExport("NAME", "output.json")
	// fmt.Println(out, err)
}

