import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport runs:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It returns combined output (stdout+stderr) from the involved commands and any error.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	loadBalancerName = strings.TrimSpace(loadBalancerName)
	outputFile = strings.TrimSpace(outputFile)

	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// Prepare commands
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun stdout -> jq stdin
	pipeReader, pipeWriter, err := os.Pipe()
	if err != nil {
		return "", fmt.Errorf("create pipe: %w", err)
	}
	defer pipeReader.Close()
	defer pipeWriter.Close()

	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Capture stderr for both commands; capture jq stdout to write to file and return as string.
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	var jqStdout bytes.Buffer

	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr
	jqCmd.Stdout = &jqStdout

	// Start jq first so it can read from the pipe.
	if err := jqCmd.Start(); err != nil {
		return aliyunStderr.String() + jqStderr.String(), fmt.Errorf("start jq: %w", err)
	}

	// Start aliyun
	if err := aliyunCmd.Start(); err != nil {
		_ = pipeWriter.Close()
		_ = jqCmd.Wait()
		return aliyunStderr.String() + jqStderr.String(), fmt.Errorf("start aliyun: %w", err)
	}

	// Wait aliyun; then close writer to signal EOF to jq.
	aliyunErr := aliyunCmd.Wait()
	_ = pipeWriter.Close()

	jqErr := jqCmd.Wait()

	// Write jq output to file (truncate/create).
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0o644); err != nil {
		combined := strings.TrimSpace(aliyunStderr.String() + jqStderr.String())
		if combined == "" {
			combined = jqStdout.String()
		}
		return combined, fmt.Errorf("write output file: %w", err)
	}

	combinedOut := jqStdout.String()
	combinedErrText := aliyunStderr.String() + jqStderr.String()

	// If either command failed, return error with stderr included.
	if aliyunErr != nil || jqErr != nil {
		var parts []string
		if aliyunErr != nil {
			parts = append(parts, fmt.Sprintf("aliyun failed: %v", aliyunErr))
		}
		if jqErr != nil {
			parts = append(parts, fmt.Sprintf("jq failed: %v", jqErr))
		}
		msg := strings.Join(parts, "; ")
		if strings.TrimSpace(combinedErrText) != "" {
			msg += ": " + strings.TrimSpace(combinedErrText)
		}
		// Return stdout+stderr for debugging.
		return strings.TrimSpace(combinedOut + "\n" + combinedErrText), fmt.Errorf("%s", msg)
	}

	// Success: return stdout plus any stderr (usually empty).
	return strings.TrimSpace(combinedOut + "\n" + combinedErrText), nil
}

func main() {
	// Example usage:
	//   go run . <LoadBalancerName> <outputFile>
	// Requires `aliyun` CLI and `jq` installed and configured.
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "usage: %s <LoadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(2)
	}

	out, err := QuerySLBAndExport(os.Args[1], os.Args[2])
	if err != nil {
		fmt.Fprintln(os.Stderr, out)
		fmt.Fprintln(os.Stderr, "error:", err)
		os.Exit(1)
	}

	if strings.TrimSpace(out) != "" {
		fmt.Println(out)
	}
}

