package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport runs:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It avoids invoking a shell and builds the pipeline using os/exec.
// It returns the jq stdout (the formatted JSON) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// Prepare commands (no shell).
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Wire pipeline: aliyun stdout -> jq stdin
	pipeReader, pipeWriter := ioPipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Capture stderr for better error messages
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Capture jq stdout (this is what we also write to file)
	var jqOut bytes.Buffer
	jqCmd.Stdout = &jqOut

	// Create output file and write jq output to it after successful run.
	// (This avoids partial files if jq fails; if you prefer streaming, use MultiWriter.)
	// Ensure directory exists? Not required by spec; rely on os.Create error.
	// Run both processes
	if err := jqCmd.Start(); err != nil {
		pipeWriter.Close()
		pipeReader.Close()
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		pipeWriter.Close()
		pipeReader.Close()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Wait for aliyun, then close writer to signal EOF to jq.
	aliyunErr := aliyunCmd.Wait()
	_ = pipeWriter.Close()

	jqErr := jqCmd.Wait()
	_ = pipeReader.Close()

	// Prefer reporting aliyun error first if it failed.
	if aliyunErr != nil {
		return jqOut.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}
	if jqErr != nil {
		return jqOut.String(), fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	// Write jq output to file
	f, err := os.Create(outputFile)
	if err != nil {
		return jqOut.String(), fmt.Errorf("failed to create output file: %w", err)
	}
	_, werr := f.Write(jqOut.Bytes())
	cerr := f.Close()
	if werr != nil {
		return jqOut.String(), fmt.Errorf("failed to write output file: %w", werr)
	}
	if cerr != nil {
		return jqOut.String(), fmt.Errorf("failed to close output file: %w", cerr)
	}

	return jqOut.String(), nil
}

// Minimal io.Pipe replacement to avoid importing extra packages in some environments.
// Uses os.Pipe which returns *os.File suitable for exec stdio.
func ioPipe() (*os.File, *os.File) {
	r, w, err := os.Pipe()
	if err != nil {
		// os.Pipe only fails in rare cases; panic is acceptable for internal helper.
		panic(err)
	}
	return r, w
}

func main() {
	// Example usage (optional). Comment out or adjust as needed.
	// out, err := QuerySLBAndExport("NAME", "output.json")
	// fmt.Println(out, err)
}

