	}
	jqCmd.Stdin = pipeReader

	// Collect stderr for diagnostics.
	var stderr bytes.Buffer
	aliyunCmd.Stderr = &stderr
	jqCmd.Stderr = &stderr

	// Write jq output to file.
	jqCmd.Stdout = f

	// Start jq first (it will wait for input).
	if err := jqCmd.Start(); err != nil {
		return stderr.String(), fmt.Errorf("start jq: %w", err)
	}

	// Start aliyun.
