package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport runs:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It avoids using a shell (prevents injection via parameters), captures the jq output,
// writes it to outputFile, and returns the jq output string (stdout) plus any error.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// Prepare commands (no shell).
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName", loadBalancerName,
	)
	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Pipe: aliyun stdout -> jq stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("create aliyun stdout pipe: %w", err)
	}
	aliyunStderr := &bytes.Buffer{}
	aliyunCmd.Stderr = aliyunStderr

	jqCmd.Stdin = aliyunStdout
	jqStderr := &bytes.Buffer{}
	jqCmd.Stderr = jqStderr

	// Capture jq stdout and also write it to file.
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("create output file: %w", err)
	}
	defer outFile.Close()

	var jqStdout bytes.Buffer
	jqCmd.Stdout = io.MultiWriter(&jqStdout, outFile)

	// Start jq first so it is ready to read.
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("start jq: %w", err)
	}
	if err := aliyunCmd.Start(); err != nil {
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("start aliyun: %w", err)
	}

	// Wait for aliyun to finish producing output.
	if err := aliyunCmd.Wait(); err != nil {
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return jqStdout.String(), fmt.Errorf("aliyun command failed: %w; stderr: %s", err, aliyunStderr.String())
	}

	// Close the pipe by waiting on jq; it will finish after reading all input.
	if err := jqCmd.Wait(); err != nil {
		return jqStdout.String(), fmt.Errorf("jq command failed: %w; stderr: %s", err, jqStderr.String())
	}

	return jqStdout.String(), nil
}

func main() {
