	outputFile = strings.TrimSpace(outputFile)

	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// Basic hardening for file path input.
	// Clean the path and reject NUL bytes (can confuse underlying syscalls).
	if strings.ContainsRune(outputFile, '\x00') {
		return "", fmt.Errorf("invalid outputFile")
	}
	outputPath := filepath.Clean(outputFile)

	// Create/truncate output file securely without invoking a shell.
	f, err := os.Create(outputPath)
	if err != nil {
		return "", fmt.Errorf("create output file: %w", err)
	}
	defer func() { _ = f.Close() }()

	// Use a timeout to avoid hanging processes.
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()

	aliyunCmd := exec.CommandContext(ctx, "aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.CommandContext(ctx, "jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe: aliyun stdout -> jq stdin
	pipeReader, pipeWriter := io.Pipe()
	defer func() { _ = pipeReader.Close() }()

	aliyunCmd.Stdout = pipeWriter

	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	jqCmd.Stdin = pipeReader

	// Capture jq stdout for return value AND write to file (like "> output.json").
	var jqStdout bytes.Buffer
	jqCmd.Stdout = io.MultiWriter(&jqStdout, f)

	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Start jq first (it will wait for input).
	if err := jqCmd.Start(); err != nil {
		_ = pipeWriter.Close()
		return "", fmt.Errorf("start jq: %w", err)
