	}

	aliyunWaitErr := aliyunCmd.Wait()
	_ = pipeWriter.Close() // always close to unblock jq

	jqWaitErr := jqCmd.Wait()

	// Handle context timeout/cancel.
	if ctx.Err() != nil {
