package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport runs:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It returns the jq stdout (the formatted JSON) and any error.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// 1) aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2) jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe: aliyun stdout -> jq stdin
	pipeReader, pipeWriter := ioPipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Capture stderr for better errors
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// jq output goes both to returned string and to file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("create output file: %w", err)
	}
	defer outFile.Close()

	var jqStdout bytes.Buffer
	jqCmd.Stdout = multiWriter(&jqStdout, outFile)

	// Start jq first so it is ready to read
	if err := jqCmd.Start(); err != nil {
		pipeReader.Close()
		pipeWriter.Close()
		return "", fmt.Errorf("start jq: %w", err)
	}

	// Start aliyun
	if err := aliyunCmd.Start(); err != nil {
		pipeReader.Close()
		pipeWriter.Close()
		_ = jqCmd.Process.Kill()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("start aliyun: %w", err)
	}

	// Wait for aliyun, then close writer to signal EOF to jq
	aliyunErr := aliyunCmd.Wait()
	_ = pipeWriter.Close()

	// Wait for jq
	jqErr := jqCmd.Wait()
	_ = pipeReader.Close()

	if aliyunErr != nil {
		return jqStdout.String(), fmt.Errorf("aliyun command failed: %w; stderr: %s", aliyunErr, aliyunStderr.String())
	}
	if jqErr != nil {
		return jqStdout.String(), fmt.Errorf("jq command failed: %w; stderr: %s", jqErr, jqStderr.String())
	}

	return jqStdout.String(), nil
}

// Minimal internal helpers (avoid extra imports in the main logic).
// These wrap os.Pipe and io.MultiWriter without exposing additional packages here.

type readCloser interface {
	Read(p []byte) (n int, err error)
	Close() error
}
type writeCloser interface {
	Write(p []byte) (n int, err error)
	Close() error
}

func ioPipe() (readCloser, writeCloser) {
	r, w, _ := os.Pipe()
	return r, w
}

type writer interface {
	Write(p []byte) (n int, err error)
}

func multiWriter(writers ...writer) writer {
	return multiW{writers: writers}
}

type multiW struct {
	writers []writer
}

func (m multiW) Write(p []byte) (int, error) {
	for _, w := range m.writers {
		if _, err := w.Write(p); err != nil {
			return 0, err
		}
	}
	return len(p), nil
}

func main() {
	// Example usage:
	// out, err := QuerySLBAndExport("NAME", "output.json")
	// fmt.Println(out, err)
}

