// QuerySLBAndExport runs:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It avoids shell execution and builds the pipeline with os/exec.
// Returns jq stdout (what would be written to the file) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// Create/overwrite output file
	outF, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("create output file: %w", err)
	}
	defer func() { _ = outF.Close() }()

	// Optional timeout to avoid hanging processes
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
	defer cancel()

	aliyunCmd := exec.CommandContext(ctx, "aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.CommandContext(ctx, "jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun -> jq
	pipeR, pipeW, err := os.Pipe()
	if err != nil {
		return "", fmt.Errorf("create pipe: %w", err)
	}
	aliyunCmd.Stdout = pipeW
	jqCmd.Stdin = pipeR

	// Capture stderr for both commands
	var aliyunErr bytes.Buffer
	var jqErr bytes.Buffer
	aliyunCmd.Stderr = &aliyunErr
	jqCmd.Stderr = &jqErr

	// jq output goes to file and also to memory for return
	var jqOut bytes.Buffer
	jqCmd.Stdout = io.MultiWriter(outF, &jqOut)

	// Start jq first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		_ = pipeR.Close()
		_ = pipeW.Close()
		return "", fmt.Errorf("start jq: %w", err)
	}

	// Start aliyun
	if err := aliyunCmd.Start(); err != nil {
		_ = pipeR.Close()
		_ = pipeW.Close()
		_ = jqCmd.Wait()
		return "", fmt.Errorf("start aliyun: %w (jq stderr: %s)", err, jqErr.String())
	}

	// Wait for aliyun, then close writer to signal EOF to jq
	aliyunWaitErr := aliyunCmd.Wait()
	_ = pipeW.Close()

	// Wait for jq
	jqWaitErr := jqCmd.Wait()
	_ = pipeR.Close()

	// Context timeout/cancel
	if ctx.Err() != nil {
		return jqOut.String(), fmt.Errorf("command context error: %w", ctx.Err())
	}

	if aliyunWaitErr != nil {
		return jqOut.String(), fmt.Errorf("aliyun failed: %w; stderr: %s", aliyunWaitErr, aliyunErr.String())
	}
	if jqWaitErr != nil {
		return jqOut.String(), fmt.Errorf("jq failed: %w; stderr: %s", jqWaitErr, jqErr.String())
	}

	return jqOut.String(), nil
