// QuerySLBAndExport runs the equivalent of:
//   aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
//
// It returns combined output (stdout+stderr) from both commands and any error encountered.
// Note: This function executes external binaries "aliyun" and "jq" which must be installed and in PATH.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	loadBalancerName = strings.TrimSpace(loadBalancerName)
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName is required")
	}
	outputFile = strings.TrimSpace(outputFile)
	if outputFile == "" {
		return "", fmt.Errorf("outputFile is required")
	}

	// Ensure output directory exists (if any).
	if dir := strings.TrimSpace(strings.TrimSuffix(outputFile, "/")); dir != "" {
		// If outputFile includes a directory, create it.
		if idx := strings.LastIndex(outputFile, string(os.PathSeparator)); idx > 0 {
			outDir := outputFile[:idx]
			if outDir != "" && outDir != "." {
				if err := os.MkdirAll(outDir, 0o755); err != nil {
					return "", fmt.Errorf("create output directory: %w", err)
				}
			}
		}
	}

