	if err != nil {
		return "", fmt.Errorf("create output file: %w", err)
	}
	defer func() { _ = f.Close() }()

	// Add a timeout to avoid hanging processes.
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
	defer cancel()

	// First command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.CommandContext(ctx, "aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.CommandContext(ctx, "jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe: aliyun stdout -> jq stdin
	pipeReader, pipeWriter := ioPipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Capture stderr for both; capture jq stdout to file and buffer.
	var combined bytes.Buffer
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

